      MergeScore bestScore = null;
      List<SegmentCommitInfo> best = null;
      boolean bestTooLarge = false;
      long bestMergeBytes = 0;
    int lim = sortedEligible.size() - maxMergeAtOnce;
    if (mergeType != MERGE_TYPE.NATURAL) {
